// NQxb_Artifact_Promote_v1__Normalize_request
// Purpose: Validate promote request shape, enforce required fields,
//          normalize selector, generate request_id.
//
// CRITICAL:
// - transition/reason arrive via artifact_payload due to ExecuteWorkflowTrigger contract
// - NEVER expect them top-level here
// - Output must surface transition/reason top-level for downstream nodes

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    const v = (c === 'x') ? r : ((r & 0x3) | 0x8);
    return v.toString(16);
  });
}

const j = $json ?? {};

const gw_action = j.gw_action ?? "artifact.promote";
const gw_workspace_id = j.gw_workspace_id ?? j.workspace_id ?? null;
const artifact_type = j.artifact_type ?? null;
const artifact_id = j.artifact_id ?? null;

// ✅ FIX: read from artifact_payload
const transition_raw = j.artifact_payload?.transition ?? null;
const reason_raw = j.artifact_payload?.reason ?? null;

// Optional passthrough
const actor_user_id_raw = j.actor_user_id ?? null;

const selector_in = (j.selector && typeof j.selector === "object") ? j.selector : {};
const hydrate = selector_in.hydrate === true;

const transition =
  (typeof transition_raw === "string") ? transition_raw.trim() : "";

const reason =
  (typeof reason_raw === "string") ? reason_raw.trim() : "";

// Normalize actor_user_id
const actor_user_id =
  (typeof actor_user_id_raw === "string" && actor_user_id_raw.trim().length > 0)
    ? actor_user_id_raw.trim()
    : null;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const fail = (code, message, details = {}) => [{
  json: {
    ok: false,
    _gw_route: "error",
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type,
    artifact_id,
    error: { code, message, details },
    timestamp: new Date().toISOString(),
  },
}];

// ---- Validation ----
if (!gw_workspace_id) {
  return fail("VALIDATION_ERROR", "gw_workspace_id is required");
}
if (!artifact_type) {
  return fail("VALIDATION_ERROR", "artifact_type is required");
}
if (!artifact_id) {
  return fail("VALIDATION_ERROR", "artifact_id is required");
}
if (!transition) {
  return fail("VALIDATION_ERROR", "transition is required", {
    source: "artifact_payload.transition",
  });
}
if (!reason || reason.length < 1 || reason.length > 280) {
  return fail("VALIDATION_ERROR", "reason is required (1..280 chars)", {
    received_length: reason.length,
  });
}
if (actor_user_id && !UUID_RE.test(actor_user_id)) {
  return fail("VALIDATION_ERROR", "actor_user_id must be a valid UUID when provided", {
    actor_user_id,
  });
}

const request_id = uuidv4();

// ---- Canonical output ----
return [{
  json: {
    ok: true,
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type: String(artifact_type),
    artifact_id: String(artifact_id),

    // ✅ surface for downstream
    transition,
    reason,

    selector: { hydrate },
    request_id,
    actor_user_id,
  },
}];

// NQxb_Artifact_Promote_v1__Resolve_Transition
// Purpose: Map a locked transition allow-list -> from_state/to_state, or reject.
//
// QPM PHASE 2 UPDATE (2026-02-01):
// - REMOVED retired_to_tree: Retired is now terminal (irreversible)
// - Only forward transitions allowed: seed->sapling->tree->retired
//
// IMPORTANT (n8n): Do NOT emit top-level reserved keys like `error`.
// Always wrap output under `{ json: ... }`.

const input = $json;

// FIX: Contract-safe fallback — transition may arrive inside artifact_payload
const transition = (
  input.transition ??
  input.artifact_payload?.transition ??
  ""
).toString().trim();

// QPM Phase 2: Only forward transitions allowed
// REMOVED: retired_to_tree (retired is terminal)
const map = {
  seed_to_sapling: { from_state: "seed", to_state: "sapling" },
  sapling_to_tree: { from_state: "sapling", to_state: "tree" },
  tree_to_retired: { from_state: "tree", to_state: "retired" },
};

const resolved = map[transition];

if (!resolved) {
  return [
    {
      json: {
        ...input,
        ok: false,
        _gw_route: "error",
        error: {
          code: "LIFECYCLE_TRANSITION_NOT_ALLOWED",
          message: `Transition not allowed: '${transition || "(empty)"}'`,
          details: {
            transition: transition || null,
            allowed: Object.keys(map),
          },
        },
      },
    },
  ];
}

return [
  {
    json: {
      ...input,
      ok: true,
      _gw_route: input._gw_route ?? "ok",
      from_state: resolved.from_state,
      to_state: resolved.to_state,
    },
  },
];

// NQxb_Artifact_Promote_v1__Enforce_Verified_State
// Purpose: Ensure artifact exists and lifecycle_status matches from_state.
//
// BUG FIX v2 (2026-02-08): MERGE_DROPS_FIELDS
// ROOT CAUSE: n8n Merge node "combineByPosition" non-deterministically drops
//             fields from input 0 — including gw_workspace_id, artifact_type, etc.
// FIX: Build ALL outputs from $node[...] references. NEVER trust $json from Merge.
//      resolveJson = authoritative source for promote context.
//      verified    = authoritative source for DB state.
//
// BUG FIX v1 (2026-02-05): FROM_STATE_MISSING
// FIX: Read from_state/to_state from $node["Resolve_Transition"].
//
// QPM PHASE 2 UPDATE (2026-02-01):
// - Captures spine.summary for QPM validation downstream

// --- AUTHORITATIVE SOURCES (never use $json from Merge) ---
const resolveNode = $node["NQxb_Artifact_Promote_v1__Resolve_Transition"];
const resolveJson = resolveNode?.json ?? {};

const verifiedNode = $node["NQxb_Artifact_Promote_v1__Verify_Current_State"];
const verifiedRaw = verifiedNode?.json ?? null;
const verified = Array.isArray(verifiedRaw)
  ? verifiedRaw[0] ?? null
  : verifiedRaw;

// --- Extract fields from authoritative sources ---
const artifactId = resolveJson.artifact_id ?? verified?.artifact_id ?? null;
const fromState = (resolveJson.from_state ?? "").toString().trim();
const toState = (resolveJson.to_state ?? "").toString().trim();
const transition = (resolveJson.transition ?? "").toString().trim();
const reason = (resolveJson.reason ?? "").toString().trim();
const actual = verified?.lifecycle_status ?? null;
const summary = verified?.summary ?? null;

// Build base context from resolveJson (reliable, not from Merge)
const baseContext = {
  gw_action: resolveJson.gw_action ?? "artifact.promote",
  gw_workspace_id: resolveJson.gw_workspace_id ?? null,
  artifact_type: resolveJson.artifact_type ?? null,
  artifact_id: artifactId,
  transition: transition,
  reason: reason,
  selector: resolveJson.selector ?? {},
  request_id: resolveJson.request_id ?? null,
  actor_user_id: resolveJson.actor_user_id ?? null,
};

// --- Pass through upstream errors ---
if (resolveJson.ok === false && resolveJson.error) {
  return [{ json: resolveJson }];
}

// --- Guards ---

if (!artifactId) {
  return [{ json: { ...baseContext, ok: false, _gw_route: "error", error: { code: "ARTIFACT_NOT_FOUND", message: "artifact_id missing after DB verify.", details: { artifact_id: null } } } }];
}

if (!fromState) {
  return [{ json: { ...baseContext, ok: false, _gw_route: "error", error: { code: "FROM_STATE_MISSING", message: "from_state missing after Resolve_Transition.", details: { from_state: resolveJson.from_state ?? null, resolve_node_available: !!resolveNode, resolve_json_keys: Object.keys(resolveJson) } } } }];
}

if (!toState) {
  return [{ json: { ...baseContext, ok: false, _gw_route: "error", error: { code: "TO_STATE_MISSING", message: "to_state missing after Resolve_Transition.", details: { to_state: resolveJson.to_state ?? null, resolve_node_available: !!resolveNode } } } }];
}

if (!actual) {
  return [{ json: { ...baseContext, ok: false, _gw_route: "error", error: { code: "LIFECYCLE_STATE_UNKNOWN", message: "Could not determine current lifecycle state from DB verify.", details: { artifact_id: artifactId, verified_row: verified ?? null } } } }];
}

// --- Enforce pre-update lifecycle correctness ---

if (actual !== fromState) {
  return [{ json: { ...baseContext, ok: false, _gw_route: "error", error: { code: "LIFECYCLE_STATE_MISMATCH", message: `Expected lifecycle '${fromState}', got '${actual}'.`, details: { artifact_id: artifactId, expected_from_state: fromState, actual_lifecycle_status: actual } } } }];
}

// --- Success: verified correctly ---
return [{
  json: {
    ...baseContext,
    ok: true,
    _gw_route: "ok",
    from_state: fromState,
    to_state: toState,
    _spine_summary: summary,
    _lifecycle_verify: {
      artifact_id: artifactId,
      verified_from_state: fromState,
      current_lifecycle_status: actual
    }
  }
}];

